sql:
SELECT f.*
FROM facilities f
WHERE f.status = 'closed' AND f.ownership_type = 'private';

SELECT f.facility_id, f.name, f.coordinates, f.status, l.action, l.details
FROM facilities f
INNER JOIN facility_logs l ON f.facility_id = l.facility_id;

SELECT DISTINCT type
FROM facilities
ORDER BY type ASC;

SELECT facilities.name, facility_types.type_name
FROM facilities
INNER JOIN facility_types ON facilities.type = facility_types.type_name;

SELECT name, ident
FROM facilities
ORDER BY name;

SELECT facility_id, name, updated_at
FROM facilities
WHERE updated_at = (
    SELECT MAX(updated_at)
    FROM facilities
);

external_knowledge:
'active' and 'in the process of maintenance' refer to the statuses 'open' and 'under maintenance' in the database;
'visitors' refer to users associated with the facilities;
'most popular' refers to facilities with the highest number of users.

sql:
SELECT DISTINCT f1.name, f1.ownership_type
FROM facilities f1
JOIN facilities f2 ON f1.ownership_type = f2.ownership_type AND f1.type = f2.type AND f1.facility_id != f2.facility_id;

SELECT name 
FROM facilities 
WHERE status = 'closed';

SELECT name, coordinates 
FROM facilities
WHERE facility_id = 1;

SELECT DISTINCT type
FROM facilities
WHERE status = 'open';

SELECT continent, AVG(elevation_ft) AS average_elevation_ft
FROM facilities
GROUP BY continent;

SELECT facility_id, elevation_ft 
FROM facilities 
WHERE elevation_ft > 50000;
